// Parsea el JSON de la IA y prepara la planilla
const raw = ($json.text || '').toString();
const clean = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
let data;
try { data = JSON.parse(clean); } catch (e) { throw new Error('La IA no devolvió JSON válido: ' + e.message); }
if (!data.dias || !Array.isArray(data.dias) || data.dias.length === 0) {
  throw new Error('El JSON no contiene días válidos');
}

const trigger = $('Nueva fila en Sheet').item.json;
const nombre = trigger.Nombre || 'crack';
const email = trigger.Email;

const headers = ['Ejercicio', 'Series', 'Reps objetivo', 'Peso usado (kg)', 'Reps hechas', 'Dificultad (facil/medio/dificil)'];
const sheets = [];
const writeData = [];

data.dias.forEach(function (dia, i) {
  const tab = 'Día ' + (i + 1);
  sheets.push({ properties: { title: tab } });
  const values = [];
  values.push([ dia.titulo || tab ]);
  values.push(headers);
  (dia.ejercicios || []).forEach(function (ej) {
    values.push([ ej.ejercicio || '', ej.series || '', ej.reps || '', '', '', '' ]);
  });
  writeData.push({ range: tab + '!A1', values: values });
});

const createBody = { properties: { title: 'Rutina FORJA - ' + nombre }, sheets: sheets };

return { json: {
  nombre: nombre,
  email: email,
  dias: data.dias,
  saludo: data.saludo || ('¡Hola ' + nombre + '!'),
  resumen: data.resumen || '',
  consejo: data.consejo || '¡A darlo todo!',
  createBody: createBody,
  writeData: writeData
} };

// Toma el ID de la planilla recién creada y arma el body para escribir los ejercicios
const create = $json; // respuesta de "Crear planilla"
const prep = $('Preparar planilla').item.json;
if (!create.spreadsheetId) { throw new Error('No se obtuvo el spreadsheetId de la planilla creada'); }
return { json: {
  spreadsheetId: create.spreadsheetId,
  spreadsheetUrl: create.spreadsheetUrl,
  body: { valueInputOption: 'RAW', data: prep.writeData }
} };

// Arma el correo con la rutina y el link a la hoja de seguimiento
const prep = $('Preparar planilla').item.json;
const create = $('Crear planilla').item.json;
const url = create.spreadsheetUrl;
const nombre = prep.nombre;
const email = prep.email;

let diasHtml = '';
prep.dias.forEach(function (dia) {
  diasHtml += '<h3 style="color:#2E9E6D;margin:22px 0 8px;font-size:17px;">' + (dia.titulo || 'Día') + '</h3>';
  diasHtml += '<ul style="margin:0 0 4px;padding-left:20px;color:#333;font-size:15px;line-height:1.6;">';
  (dia.ejercicios || []).forEach(function (ej) {
    const nota = ej.nota ? ' <em style="color:#777;">(' + ej.nota + ')</em>' : '';
    diasHtml += '<li style="margin-bottom:5px;"><strong>' + ej.ejercicio + '</strong> — ' + ej.series + ' series × ' + ej.reps + ' reps' + nota + '</li>';
  });
  diasHtml += '</ul>';
});

const html =
'<div style="font-family:Arial,sans-serif;background-color:#f7f9fa;padding:30px;">' +
  '<div style="max-width:600px;margin:0 auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 4px 10px rgba(0,0,0,0.05);">' +
    '<div style="background:#2E9E6D;color:#fff;padding:30px 20px;text-align:center;">' +
      '<h1 style="margin:0;font-size:24px;">¡Tu rutina está lista! 🏋️</h1>' +
    '</div>' +
    '<div style="padding:30px;">' +
      '<p style="font-size:16px;color:#333;margin-top:0;">' + prep.saludo + '</p>' +
      '<p style="font-size:15px;color:#333;line-height:1.5;">' + prep.resumen + '</p>' +
      diasHtml +
      '<div style="background:#eaf5f0;border-radius:8px;padding:20px;margin:24px 0;text-align:center;">' +
        '<p style="margin:0 0 14px;font-size:15px;color:#1a5c3f;"><strong>📊 Registra tu progreso</strong><br>Anota el peso, las repeticiones y la dificultad de cada ejercicio en tu hoja personal:</p>' +
        '<a href="' + url + '" style="background:#2E9E6D;color:#fff;text-decoration:none;padding:14px 26px;border-radius:8px;font-weight:bold;display:inline-block;">Abrir mi hoja de seguimiento</a>' +
      '</div>' +
      '<p style="font-size:13px;color:#888;">En tu próximo seguimiento, ajustaremos tus cargas usando esos datos reales.</p>' +
      '<p style="font-size:15px;color:#333;margin-top:18px;">' + prep.consejo + '</p>' +
    '</div>' +
    '<div style="padding:20px;text-align:center;color:#888;font-size:14px;border-top:1px solid #eee;">' +
      'Con cariño,<br><strong>Equipo Forja Rutinas 💪</strong>' +
    '</div>' +
  '</div>' +
'</div>';

return { json: { email: email, nombre: nombre, html: html, hoja_url: url } };
